import React, { useEffect, useState } from 'react'
import {Link } from 'react-router-dom';
import { CButton } from "@coreui/react";
import { deleteUser, getAllUser } from 'src/components/services/UserApi';
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt } from "../../../utils/Common";
import { tableUserConstant } from './tableUserConstant';
import DataTable from "react-data-table-component";
import { customStyles } from '../../../utils/tableCustomStyles';
import authService from 'src/auth/auth.service';

const MySwal = withReactContent(alertPopUp);

function UserList() {
    const [rowData, setRowData] = useState([]);

    useEffect(()=>{
        fetchUser();
    },[])

    const handleDelete = async(id) => {
        const data = await deleteUser(id);
        if(data?.code === 200){
            fetchUser();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const fetchUser = async () =>{
        let user = await getAllUser();
        if(user?.code === 200){
            setRowData(user?.results)
        }
    }

    return (
        <div className='row'>
            <div className="col2Large">
                <DataTable
                    title="User"
                    columns={tableUserConstant(handleConfirmModal)}
                    data={rowData}
                    customStyles={customStyles}
                    //actions={this.actionButton()}
                    pagination
                    paginationPerPage={10}
                    pointerOnHover
                    fixedHeader
                    noContextMenu
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                />
            </div>
            {authService.getPermission("USER_CREATE") && <div className='col-sm-12'>
                <Link to={"/user/create"}>
                    <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                        {"+ Create User"}
                    </CButton>
                </Link>
            </div>}
        </div>
    )
}

export default UserList
